   403	func determineAttributionMethod(claim waterfall.ClaimInterface) string {
   404		switch claim.GetAttributionModule() {
   405		case "facebook", "instagram":
   406			return "SRN"
   407		case "facebook-deeplink":
   408			return "DEEPLINK"
   409		case "facebook-install-referrer":
   410			return "GPIR"
