   418	// GetFBAttributionForEventTime returns the previous Facebook attribution details for event-time enrichment.
   419	// Two-way approach:
   420	//   - Non-restricted (facebook/instagram/facebook-deeplink): Uses details passed directly from Control
   421	//   - Restricted: Falls back to device-keyed Redis cache lookup
   422	//
   423	// Returns nil if no attribution details are available.
   424	func (handler *ReconcileHandler) GetFBAttributionForEventTime(ctx context.Context, watsonRequest structs.WatsonRequest) *restrictedxna.ReducedRestrictedClaim {
   425		if !watsonRequest.IsFB {
   426			return nil
   427		}
   428	
   429		// Non-restricted path: Control passed the details directly
   430		if watsonRequest.FBAttributionDetails != nil {
   431			details := watsonRequest.FBAttributionDetails
   432			return &restrictedxna.ReducedRestrictedClaim{
   433				AdID:                  details.AdID,
   434				ClickTime:             details.ClickTime,
   435				AuditingToken:         details.AuditingToken,
   436				AttributionMethod:     details.AttributionMethod,
   437				InstallTime:           details.InstallTime,
   438				GoogleInstallReferrer: details.GoogleInstallReferrer,
   439				MetaInstallReferrer:   details.MetaInstallReferrer,
   440				InstallID:             watsonRequest.Identifiers["kochava_device_id"],
   441			}
   442		}
   443	
   444		// Restricted path: look up from encrypted Redis cache
   445		if handler.DeviceClaimStorageGetter == nil {
   446			handler.Logger.Warn("is_fb=true with no attribution details and no device claim getter configured")
   447			return nil
   448		}
   449	
   450		deviceID, ok := watsonRequest.Identifiers["kochava_device_id"]
   451		if !ok || deviceID == "" {
   452			handler.Logger.Warn("is_fb=true but no kochava_device_id in request")
   453			return nil
   454		}
   455	
   456		deviceKey := "device:" + deviceID + ":install"
   457		cachedClaim, err := handler.DeviceClaimStorageGetter.Get(ctx, deviceKey)
   458		if err != nil {
   459			handler.Logger.Debug("unable to get device-keyed restricted claim from cache", zap.String("device_key", deviceKey), zap.Error(err))
   460			return nil
